from collections import Counter

def permute_unique(nums):
    result = []
    def backtrack(path, counts):
        if len(path) == len(nums):
            result.append(list(path))
            return
        for num in counts:
            if counts[num] > 0:
                path.append(num)
                counts[num] -= 1
                backtrack(path, counts)
                counts[num] += 1
                path.pop()
    backtrack([], Counter(nums))
    return result

