import heapq

def prim(graph, start):
    mst = []
    visited = {start}
    edges = [(cost, start, to) for to, cost in graph[start].items()]
    heapq.heapify(edges)
    total_cost = 0
    while edges:
        cost, frm, to = heapq.heappop(edges)
        if to not in visited:
            visited.add(to)
            mst.append((frm, to, cost))
            total_cost += cost
            for to_next, cost_next in graph[to].items():
                if to_next not in visited:
                    heapq.heappush(edges, (cost_next, to, to_next))
    return mst, total_cost

def kruskal(graph):
    parent = {i: i for i in graph['vertices']}
    def find(i):
        if parent[i] == i: return i
        return find(parent[i])
    def union(i, j):
        root_i = find(i)
        root_j = find(j)
        if root_i != root_j: parent[root_i] = root_j
    mst, total_cost = [], 0
    edges = sorted(graph['edges'], key=lambda item: item[2])
    for u, v, weight in edges:
        if find(u) != find(v):
            union(u, v)
            mst.append((u, v, weight))
            total_cost += weight
    return mst, total_cost

def remove_duplicates(nums):
    if not nums: return 0
    k = 1
    for i in range(1, len(nums)):
        if nums[i] != nums[i - 1]:
            nums[k] = nums[i]
            k += 1
    return k

from collections import Counter

def find_all_anagrams(s, p):
    ns, np = len(s), len(p)
    if ns < np: return []
    p_count, s_count = Counter(p), Counter()
    result = []
    for i in range(ns):
        s_count[s[i]] += 1
        if i >= np:
            if s_count[s[i - np]] == 1:
                del s_count[s[i - np]]
            else:
                s_count[s[i - np]] -= 1
        if p_count == s_count:
            result.append(i - np + 1)
    return result

def unique_paths(m, n):
    dp = [[1] * n for _ in range(m)]
    for i in range(1, m):
        for j in range(1, n):
            dp[i][j] = dp[i-1][j] + dp[i][j-1]
    return dp[m-1][n-1]

def min_path_sum(grid):
    m, n = len(grid), len(grid[0])
    for i in range(1, m): grid[i][0] += grid[i-1][0]
    for j in range(1, n): grid[0][j] += grid[0][j-1]
    for i in range(1, m):
        for j in range(1, n):
            grid[i][j] += min(grid[i-1][j], grid[i][j-1])
    return grid[-1][-1]

