int knapsack(int W, const std::vector<int>& wt, const std::vector<int>& val) {
    int n = val.size();
    std::vector<std::vector<int>> K(n + 1, std::vector<int>(W + 1));
    for (int i = 0; i <= n; i++) {
        for (int w = 0; w <= W; w++) {
            if (i == 0 || w == 0) K[i][w] = 0;
            else if (wt[i-1] <= w)
                K[i][w] = std::max(val[i-1] + K[i-1][w-wt[i-1]], K[i-1][w]);
            else
                K[i][w] = K[i-1][w];
        }
    }
    return K[n][W];
}

