bool isSafe(int row, int col, std::vector<std::string>& board, int n) {
    int r = row, c = col;
    while(r >= 0 && c >= 0) if(board[r--][c--] == 'Q') return false;
    r = row, c = col;
    while(c >= 0) if(board[r][c--] == 'Q') return false;
    r = row, c = col;
    while(r < n && c >= 0) if(board[r++][c--] == 'Q') return false;
    return true;
}

void solve(int col, std::vector<std::string>& board, std::vector<std::vector<std::string>>& ans, int n) {
    if(col == n) { ans.push_back(board); return; }
    for(int row = 0; row < n; row++) {
        if(isSafe(row, col, board, n)) {
            board[row][col] = 'Q';
            solve(col + 1, board, ans, n);
            board[row][col] = '.';
        }
    }
