int maxArea(const std::vector<int>& height) {
    int max_water = 0;
    int left = 0, right = height.size() - 1;
    while (left < right) {
        int h = std::min(height[left], height[right]);
        max_water = std::max(max_water, h * (right - left));
        if (height[left] < height[right]) {
            left++;
        } else {
            right--;
        }
    }
    return max_water;
}

